function doStartRealPlay() {
    var oWndInfo = WebVideoCtrl.I_GetWindowStatus(g_iWndIndex2);
    var streamTypeSelect = document.getElementById('streamType');
    
    if (!g_szDeviceIdentify2) {
        if (typeof mediaLog === 'function') mediaLog('请先登录', 'error');
        return;
    }
    
    if (!streamTypeSelect) {
        console.error('[WASM] streamType select not found');
        return;
    }
    
    var streamType = parseInt(streamTypeSelect.value, 10);
    var iChannelID = g_iChannelID || 1;
    g_iStreamType = streamType;
    
    // v7.98: 直连模式，不设置 cookie，SDK 根据 iStreamType 参数处理
    
    console.log('[WASM] doStartRealPlay: stream=' + streamType + ' channel=' + iChannelID);
    if (typeof mediaLog === 'function') mediaLog('开始预览', 'info');

    var startRealPlay = function() {
        WebVideoCtrl.I_StartRealPlay(g_szDeviceIdentify2, {
            iStreamType: streamType,
            iChannelID: iChannelID,
            bZeroChannel: false,
            bProxy: false,
            success: function() {
                g_bPlaying2 = true;
                console.log('[WASM] I_StartRealPlay SUCCESS');
                if (typeof mediaLog === 'function') mediaLog('预览成功', 'success');
                if (window.updateWasmStatus) window.updateWasmStatus('playing');
            },
            error: function(status, xmlDoc) {
                g_bPlaying2 = false;
                var errMsg = 'status=' + (status || '未知');
                try {
                    if (xmlDoc) {
                        var sc = xmlDoc.getElementsByTagName('statusCode');
                        var ss = xmlDoc.getElementsByTagName('statusString');
                        if (sc.length > 0) errMsg = 'code=' + sc[0].textContent;
                        if (ss.length > 0) errMsg += ' ' + ss[0].textContent;
                    }
                } catch(e) {}
                console.error('[WASM] I_StartRealPlay FAILED - ' + errMsg);
                if (typeof mediaLog === 'function') mediaLog('播放失败: ' + errMsg, 'error');
                if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
            }
        });
    };

    if (oWndInfo != null) {
        WebVideoCtrl.I_Stop({
            success: function() { startRealPlay(); },
            error: function() { startRealPlay(); }
        });
    } else {
        startRealPlay();
    }
}
